1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
4	type QuoteResult = { premium: number };
5	
6	const PROCESSING_FEE = 5;
7	const FIRST_INSURANCE_RATE = 0.1;
8	
9	const ITEM_BASE_PREMIUMS: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	  rune: 25,
15	  moonstone: 25,
16	};
17	
18	const BLOCK_SIZE = 3;
19	const BLOCK_BASE_PREMIUM = 60;
20	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
21	
22	const CURSE_RATE = 0.5;
23	const HIGH_ENCHANTMENT_RATE = 0.3;
24	const HIGH_ENCHANTMENT_THRESHOLD = 5;
25	
26	const sumBy = <T>(items: T[], f: (x: T) => number): number =>
27	  items.reduce((acc, x) => acc + f(x), 0);
28	
29	const baseFor = (item: Item): number => ITEM_BASE_PREMIUMS[item.type];
30	
31	const surchargeFor = (item: Item): number => {
32	  const base = baseFor(item);
33	  const curse = item.cursed ? base * CURSE_RATE : 0;
34	  const highEnch = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_RATE : 0;
35	  return curse + highEnch;
36	};
37	
38	const totalSurchargeFor = (items: Item[]): number => sumBy(items, surchargeFor);
39	
40	const premiumFor = (totalBase: number, totalSurcharge: number): number =>
41	  totalBase + totalSurcharge + Math.ceil(totalBase * FIRST_INSURANCE_RATE) + PROCESSING_FEE;
42	
43	const groupByType = (items: Item[]): Map<string, Item[]> => {
44	  const groups = new Map<string, Item[]>();
45	  for (const item of items) {
46	    const group = groups.get(item.type) ?? [];
47	    group.push(item);
48	    groups.set(item.type, group);
49	  }
50	  return groups;
51	};
52	
53	const baseForGroup = (type: string, group: Item[]): number => {
54	  if (COMPONENT_TYPES.has(type) && group.length === BLOCK_SIZE) return BLOCK_BASE_PREMIUM;
55	  return sumBy(group, baseFor);
56	};
57	
58	const totalBaseFor = (items: Item[]): number =>
59	  Array.from(groupByType(items)).reduce(
60	    (total, [type, group]) => total + baseForGroup(type, group),
61	    0,
62	  );
63	
64	const quoteFor = (step: QuoteStep): QuoteResult => ({
65	  premium: premiumFor(totalBaseFor(step.items), totalSurchargeFor(step.items)),
66	});
67	
68	export const processScenario = (input: Scenario): { results: QuoteResult[] } => {
69	  return { results: input.steps.map(quoteFor) };
70	};
